int maxPuntuacion(int N, int cara1, int cara2, vector<pair<int, int>> canciones) {
    // Inicializar variables necesarias
    int maxPuntuacion = 0;
    // Función recursiva para explorar combinaciones
    function<void(int, int, int, int)> backtrack = [&](int index, int duracion1, int duracion2, int puntuacion) {
        // Condición de poda
        if (duracion1 > cara1 || duracion2 > cara2) return;
        // Actualizar puntuación máxima
        maxPuntuacion = max(maxPuntuacion, puntuacion);
        // Explorar siguientes canciones
        for (int i = index; i < N; ++i) {
            // Llamada recursiva
            backtrack(i + 1, duracion1 + canciones[i].first, duracion2, puntuacion + canciones[i].second);
            backtrack(i + 1, duracion1, duracion2 + canciones[i].first, puntuacion + canciones[i].second);
        }
    };
    // Iniciar backtracking
    backtrack(0, 0, 0, 0);
    return maxPuntuacion;
}
